UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('walking-knee-hug', 'Hold for one count only; coach says "tall tree, knee hug."', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('walking-quad-pull', 'Use wall support or perform stationary.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('leg-swings-front-back', 'Use support and small swings.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('leg-swings-lateral', 'Hold support and use smaller swings.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('9090-hip-switch', 'Hands behind body; make it "windshield wipers."', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('shin-box-switch', 'Use hands behind body and wider angles.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('shin-box-get-up', 'Use hands and partial rise only.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('hip-cars', 'Quadruped version with small circle.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('adductor-rockback', 'Keep range small and playful; "slide hips back."', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('frog-rockback', 'Narrower knee width and shorter range.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('cossack-shift', 'Shallow lateral shifts only.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('deep-squat-pry', 'Squat to box or hold support.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('squat-to-stand-with-reach', 'Use object between feet and shallow squat.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('lateral-lunge-shift', 'Shallow side shift with hands forward.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

