UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'teen' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('walking-knee-hug', 'Use smaller knee lift and wall support if needed. Avoid yanking into end range; use active hip flexion plus gentle assist.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('walking-quad-pull', 'Reduce heel pull and keep hold brief. Use active glute squeeze and short hold; avoid passive knee yanking.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('leg-swings-front-back', 'Keep range modest and gradual. Keep controlled range; avoid end-range whipping.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('leg-swings-lateral', 'Keep range low and controlled. Avoid end-range whipping; maintain control.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('9090-hip-switch', 'Sit on a pad or yoga block to reduce hip demand. Avoid collapsing into end range; use active controlled rotation.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('shin-box-switch', 'Sit on a pad or use hand support. Avoid flopping into end range; use active control.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('shin-box-get-up', 'Hands assisted; reduce range. Active controlled range; do not sink into joints.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('hip-cars', 'Quadruped or standing with wall. Smaller active circle with control; avoid passive end-range hanging.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('adductor-rockback', 'Use pad under knee and shorter range. Avoid hanging into end range; use controlled rock.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('frog-rockback', 'Use mat/pad and reduce range. Use active controlled range, not passive sinking.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('cossack-shift', 'Use support or reduce stance width. Avoid sinking into end range; keep active adductor/hip control.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('deep-squat-pry', 'Heel-elevated squat pry or hold upright support. Avoid passive hanging; actively hold foot/knee/hip position.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('squat-to-stand-with-reach', 'Hold ankles or shins instead of toes; elevate heels if needed. Avoid passive end-range hanging; maintain active foot/knee/hip control.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('lateral-lunge-shift', 'Reduce stance width and depth. Avoid sinking passively into adductors; keep active hip control.', 'No sex-based default; scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'teen';

