-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for athletic development.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('walking-knee-hug', 'Walking knee hugs combine hip flexion, glute stretch, upright posture, and single-leg balance. The Prehab Guys cue the athlete to stand tall, bring the knee toward the chest, and avoid leaning backward; a military dynamic-warm-up reference also lists dropping the chest and failing to dorsiflex the foot as common mistakes.', 'Belongs in Integrate (dynamic_hip_mobility) — early dynamic hip access with single-leg balance before higher-intent lower-body work.', 'Early integrated hip mobility before sprinting, jumping, tumbling, squatting, lunging, or general lower-body work.', 'Do not yank the knee aggressively, drop the chest, or rush without balance before sprint or jump work.', 'Scale by balance, hip comfort, sport demand, tissue tolerance, and symptoms.'),
  ('walking-quad-pull', 'Walking quad pulls prepare the anterior thigh and hip-flexor line while the athlete maintains balance and upright posture. The Prehab Guys cue grabbing the ankle, pulling the heel toward the glute, keeping the thigh straight, reaching overhead with the opposite arm, and avoiding knee flare or leaning; the DVIDS version similarly notes keeping the chest up and knees together.', 'Belongs in Integrate (dynamic_quad_hip_flexor) — dynamic anterior-chain access with balance before sprint, jump, or squat work.', 'Integrated dynamic quad/hip-flexor access before sprinting, tumbling takeoffs, squatting, lunging, jumping, and lower-body strength.', 'Do not yank the ankle, wing the knee outward, or arch the low back for more range.', 'Scale by quad length, knee comfort, balance, and sport demand.'),
  ('leg-swings-front-back', 'Front/back leg swings prepare the hip through flexion and extension while increasing dynamic range for the hamstrings, glutes, hip flexors, and running/takeoff positions. Elite Performance Institute cues standing tall, holding support if needed, swinging the leg forward and backward in control, avoiding excessive leaning, and using 10–20 swings per direction before running or lifting.', 'Belongs in Mobilize (hip_swing_sagittal) — sagittal dynamic hip prep before locomotion or power work.', 'Dynamic sagittal hip prep before sprinting, tumbling, jumping, squatting, lunging, or running-based work.', 'Do not force range, lean excessively, or turn swings into ballistic kicking.', 'Scale by hamstring/hip-flexor tolerance, control, and sport demand.'),
  ('leg-swings-lateral', 'Lateral leg swings prepare the groin/adductor and lateral-hip tissues for frontal-plane motion. Special Olympics provides a forward and lateral leg swings dynamic warm-up video, while Elite Performance Institute notes leg swings can be performed side-to-side with controlled range rather than forced flexibility.', 'Belongs in Mobilize (hip_swing_frontal) — frontal-plane dynamic hip prep before lateral athletic work.', 'Frontal-plane hip prep before cutting, lateral shuffling, tumbling takeoffs, Cossack work, lateral lunges, or agility.', 'Do not twist the torso heavily or swing aggressively into groin pain.', 'Scale by groin tolerance, lateral movement needs, and control.'),
  ('9090-hip-switch', 'The 90/90 position trains one hip in external rotation and the other in internal rotation, making it useful for hip rotation access and movement transitions. The Prehab Guys describe beginning seated with both knees bent, hinging toward the front knee, then rotating both legs to the other side while keeping the heels on the ground.', 'Belongs in Mobilize (hip_rotation) — seated IR/ER access before squat, lunge, sprint, or lateral prep.', 'Hip rotation access before squatting, sprinting, tumbling, cutting, lateral movement, or ground transitions.', 'Do not force knees to the floor or flop between sides with momentum.', 'Scale by hip structure, rotation access, knee comfort, and symptoms.'),
  ('shin-box-switch', 'The shin box switch is a progression from simple 90/90 hip rotation into a smoother rotational transition. Kruse Elite describes the goal as switching the knees to the other side so the hips rotate without needing hand support, while keeping a long spine and avoiding rounding.', 'Belongs in Mobilize (hip_rotation_integrated) — integrated hip rotation with pelvic/trunk control before ground transitions.', 'After basic 90/90 work when the athlete can control hip rotation without knee pain.', 'Do not throw knees with momentum or round the spine to avoid hip rotation.', 'Scale by hip anatomy, knee comfort, and trunk control.'),
  ('shin-box-get-up', 'The shin box get-up moves beyond passive hip mobility by making the athlete control rotation, hip extension, trunk position, and transition from the floor. Elite Performance Institute describes it as a drill for hip internal/external rotation, lower-body control, and smooth transitions, with scaling from hand assistance to loaded progressions.', 'Belongs in Integrate (hip_transition) — rotational hip mobility linked to ground-to-kneeling transitions.', 'When athletes need hip rotation plus transition control before tumbling, ninja, squatting, or athletic ground movement.', 'Do not drop into the bottom, use momentum, or load heavily before high-output work.', 'Scale by hip/knee tolerance, ground transition ability, and fatigue cost.'),
  ('hip-cars', 'Hip CARs train active motion through hip flexion, abduction, rotation, extension, and adduction while the rest of the body stays organized. The Prehab Guys cue quadruped hip CARs as lifting the leg and moving through extension, external rotation, abduction, and flexion while trying to isolate the hip; their standing version adds a balance challenge while moving through hip flexion, abduction, internal rotation, extension, and adduction.', 'Belongs in Mobilize (hip_cars) — active hip range scan before integrated or power work.', 'Active hip scan and mobility before sprinting, squatting, tumbling, cutting, or lower-body strength.', 'Do not rush circles, arch the low back, or hang passively at end range.', 'Scale by hip control, balance demand, and pinching symptoms.'),
  ('adductor-rockback', 'Adductor rockbacks target the adductors/groin while the quadruped position allows the athlete to control pelvic and spinal position. The Prehab Guys cue setting up on hands and knees, extending one leg to the side with the knee straight, finding a neutral pelvis, then shifting the hips backward comfortably.', 'Belongs in Mobilize (adductor_mobility) — groin/adductor access with neutral spine before frontal-plane work.', 'Adductor/groin prep before lateral movement, Cossack shifts, squats, lunges, cutting, and tumbling takeoffs.', 'Do not force groin stretch or round the low back for more range.', 'Scale by groin history, hip structure, and lateral sport demands.'),
  ('frog-rockback', 'Frog rockbacks target hip abduction and the adductor/groin region while the athlete practices pelvic control. The Prehab Guys describe the dynamic frog stretch as starting in tabletop with knees spread comfortably, rocking back until a groin/adductor stretch is felt, and keeping the back flat rather than rounding.', 'Belongs in Mobilize (adductor_mobility) — short adductor/groin access with neutral spine.', 'Groin/adductor access before squat, lateral movement, Cossack, tumbling takeoff, or cutting work.', 'Do not force knees too wide or round the low back aggressively.', 'Scale by pelvic/groin comfort, hip structure, and adductor tolerance.'),
  ('cossack-shift', 'The Cossack pattern prepares the body for lateral loading, adductor length, hip control, ankle dorsiflexion, and knee tracking. The Prehab Guys cue shifting weight to one side into a deep lateral lunge while trying to sit back on the heel and keeping the opposite leg straight; for Prepare & Access, use a lower-amplitude version rather than maximal depth.', 'Belongs in Integrate (frontal_plane_mobility) — shallow frontal-plane squat shift before agility or lateral power.', 'Frontal-plane prep before lateral lunges, cutting, agility, squatting, landing, and lateral power work.', 'Do not force depth or collapse the knee inward before reactive agility.', 'Scale by groin/hip/ankle tolerance and lateral sport demands.'),
  ('deep-squat-pry', 'Deep squat prying exposes the athlete to the bottom squat position while gently opening hips and ankles. Muscle & Strength describes the deep squat prying drill as a dynamic warm-up movement that activates lower-body muscles and promotes mobility by rocking side to side and using the elbows to open the hips.', 'Belongs in Integrate (squat_access) — squat-bottom mobility before squat, jump, or landing work.', 'Squat-bottom access before squatting, jumping, landing, tumbling takeoffs, or lower-body strength.', 'Do not turn into a long static hold or force depth before Output.', 'Scale by squat anatomy, ankle/hip access, and symptoms.'),
  ('squat-to-stand-with-reach', 'Squat-to-stand with reach connects a forward fold/hinge, deep squat, thoracic reach, and return to standing. Physitrack''s deep squat to arm reach and stand cues bending to touch a ball, dropping hips into a squat, raising one arm while following it with the eyes, raising the other arm into a Y, and standing with the chest tall.', 'Belongs in Integrate (squat_to_stand) — links hinge, squat bottom, and thoracic reach before loaded squat work.', 'Integrated squat prep before squats, jumps, tumbling, lower-body strength, and overhead work.', 'Do not force hamstring stretch or round aggressively to reach toes.', 'Scale by hamstring range, squat depth, trunk control, and symptoms.'),
  ('lateral-lunge-shift', 'Lateral lunge shifts prepare the athlete to load one hip while lengthening the opposite adductor line, which is directly relevant to cutting, deceleration, lateral shuffle, and frontal-plane strength. The Prehab Guys'' walking Cossack/lateral-lunge family cues beginning wide, shifting weight to one side, sitting back onto the heel, and keeping the opposite leg straight.', 'Belongs in Integrate (lateral_lunge_prep) — frontal-plane loading pattern before agility or cutting.', 'Controlled frontal-plane prep before agility, cutting, lateral bounds, lower-body strength, tumbling takeoffs, or sport change-of-direction work.', 'Do not push too deep too soon or collapse the loaded knee before reactive agility.', 'Scale by groin tolerance, knee tracking, and lateral sport demands.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
